import json


def lambda_handler(event, context):
    """
    AWS Lambda function that serves user data as JSON for a single-page application.
    Configured with permissive CORS headers for development flexibility.
    """
    
    # Define CORS headers to allow requests from any origin
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With, X-Api-Key",
        "Access-Control-Max-Age": "86400",
        "Content-Type": "application/json"
    }
    
    # Handle preflight OPTIONS request
    http_method = event.get("httpMethod") or event.get("requestContext", {}).get("http", {}).get("method", "GET")
    
    if http_method == "OPTIONS":
        return {
            "statusCode": 200,
            "headers": cors_headers,
            "body": ""
        }
    
    # Extract path and query parameters
    path_parameters = event.get("pathParameters") or {}
    query_parameters = event.get("queryStringParameters") or {}
    
    # Determine the resource path
    resource_path = event.get("path", "/")
    
    try:
        # Route handling
        if http_method == "GET":
            if resource_path == "/users" or resource_path == "/":
                response_body = get_all_users(query_parameters)
            elif path_parameters.get("userId"):
                response_body = get_user_by_id(path_parameters["userId"])
            elif resource_path.startswith("/users/") and len(resource_path.split("/")) >= 3:
                user_id = resource_path.split("/")[2]
                response_body = get_user_by_id(user_id)
            else:
                response_body = get_all_users(query_parameters)
                
        elif http_method == "POST":
            body = json.loads(event.get("body", "{}") or "{}")
            response_body = create_user(body)
            return {
                "statusCode": 201,
                "headers": cors_headers,
                "body": json.dumps(response_body, default=str)
            }
            
        elif http_method == "PUT":
            user_id = path_parameters.get("userId")
            if not user_id and resource_path.startswith("/users/"):
                user_id = resource_path.split("/")[2]
            body = json.loads(event.get("body", "{}") or "{}")
            response_body = update_user(user_id, body)
            
        elif http_method == "DELETE":
            user_id = path_parameters.get("userId")
            if not user_id and resource_path.startswith("/users/"):
                user_id = resource_path.split("/")[2]
            response_body = delete_user(user_id)
            
        else:
            return {
                "statusCode": 405,
                "headers": cors_headers,
                "body": json.dumps({"error": "Method not allowed"})
            }
        
        return {
            "statusCode": 200,
            "headers": cors_headers,
            "body": json.dumps(response_body, default=str)
        }
        
    except UserNotFoundException as e:
        return {
            "statusCode": 404,
            "headers": cors_headers,
            "body": json.dumps({"error": str(e)})
        }
    except ValidationError as e:
        return {
            "statusCode": 400,
            "headers": cors_headers,
            "body": json.dumps({"error": str(e)})
        }
    except Exception as e:
        print(f"Unhandled error: {str(e)}")
        return {
            "statusCode": 500,
            "headers": cors_headers,
            "body": json.dumps({"error": "Internal server error"})
        }


class UserNotFoundException(Exception):
    pass


class ValidationError(Exception):
    pass


