def get_all_users(query_params):
    """Retrieve all users with optional filtering and pagination."""
    users = list(MOCK_USERS.values())
    
    # Filter by role if specified
    role_filter = query_params.get("role")
    if role_filter:
        users = [u for u in users if u["role"] == role_filter]
    
    # Search by name or email
    search_query = query_params.get("search", "").lower()
    if search_query:
        users = [
            u for u in users
            if search_query in u["firstName"].lower()
            or search_query in u["lastName"].lower()
            or search_query in u["email"].lower()
            or search_query in u["username"].lower()
        ]
    
    # Pagination
    page = int(query_params.get("page", "1"))
    page_size = int(query_params.get("pageSize", "10"))
    total = len(users)
    start = (page - 1) * page_size
    end = start + page_size
    paginated_users = users[start:end]
    
    return {
        "data": paginated_users,
        "pagination": {
            "page": page,
            "pageSize": page_size,
            "total": total,
            "totalPages": max(1, -(-total // page_size))  # ceiling division
        }
    }


def get_user_by_id(user_id):
    """Retrieve a single user by ID."""
    if user_id not in MOCK_USERS:
        raise UserNotFoundException(f"User with id '{user_id}' not found")
    return {"data": MOCK_USERS[user_id]}


def create_user(body):
    """Create a new user."""
    required_fields = ["username", "email", "firstName", "lastName"]
    missing = [f for f in required_fields if f not in body]
    if missing:
        raise ValidationError(f"Missing required fields: {', '.join(missing)}")
    
    # Generate new ID
    new_id = str(max(int(k) for k in MOCK_USERS.keys()) + 1)
    
    new_user = {
        "id": new_id,
        "username": body["username"],
        "email": body["email"],
        "firstName": body["firstName"],
        "lastName": body["lastName"],
        "role": body.get("role", "viewer"),
        "avatar": f"https://api.dicebear.com/7.x/avataaars/svg?seed={body['username']}",
        "preferences": body.get("preferences", {
            "theme": "light",
            "language": "en",
            "notifications": True
        }),
        "createdAt": "2024-12-03T00:00:00Z",
        "lastLogin": None
    }
    
    MOCK_USERS[new_id] = new_user
    return {"data": new_user, "message": "User created successfully"}


def update_user(user_id, body):
    """Update an existing user."""
    if not user_id:
        raise ValidationError("User ID is required")
    if user_id not in MOCK_USERS:
        raise UserNotFoundException(f"User with id '{user_id}' not found")
    
    user = MOCK_USERS[user_id]
    
    # Only update allowed fields
    updatable_fields = ["username", "email", "firstName", "lastName", "role", "preferences"]
    for field in updatable_fields:
        if field in body:
            user[field] = body[field]
    
    MOCK_USERS[user_id] = user
    return {"data": user, "message": "User updated successfully"}


def delete_user(user_id):
    """Delete a user."""
    if not user_id:
        raise ValidationError("User ID is required")
    if user_id not in MOCK_USERS:
        raise UserNotFoundException(f"User with id '{user_id}' not found")
    
    deleted_user = MOCK_USERS.pop(user_id)
    return {"data": {"id": deleted_user["id"]}, "message": "User deleted successfully"}


